resource "aws_apprunner_auto_scaling_configuration_version" "example" {
  auto_scaling_configuration_name = "example-scaling-config"
  max_concurrency                 = 100
  max_size                        = 10
  min_size                        = 1

  tags = {
    Name = "example-app-scaling-config"
  }
}

resource "aws_apprunner_service" "example" {
  service_name = "example-web-app"

  auto_scaling_configuration_arn = aws_apprunner_auto_scaling_configuration_version.example.arn

  source_configuration {
    authentication_configuration {
      # Connection ARN for your source code repository (e.g., GitHub)
      # connection_arn = "arn:aws:apprunner:us-east-1:123456789012:connection/github-conn/v1"
    }

    code_repository {
