      name  = "DEPLOY_TARGET"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/my-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  source_version = "main"

  tags = {
    Environment = "Test"
  }
}

