resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["logs:*", "s3:*", "codecommit:*"]
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Terraform managed CodeBuild project with secondary sources and artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "STAGING"
    }

    environment_variable {
      name  = "VAR_CONTEXT"
      value = "APPLICATION_BUILD"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
  }

  secondary_sources {
    source_identifier = "helper_lib"
    type              = "GITHUB"
    location          = "https://github.com/example/helper-library.git"
    git_clone_depth   = 1
  }

  secondary_sources {
    source_identifier = "config_repo"
    type              = "GITHUB"
    location          = "https://github.com/example/config-repo.git"
    git_clone_depth   = 1
  }

  secondary_artifacts {
    artifact_identifier = "webapp_build"
    type                = "S3"
    location            = "my-output-bucket"
    packaging           = "ZIP"
    path                = "/builds/webapp"
    name                = "webapp-v1.zip"
  }

  secondary_artifacts {
    artifact_identifier = "api_build"
    type                = "S3"
    location            = "my-output-bucket"
    packaging           = "ZIP"
    path                = "/builds/api"
    name                = "api-v1.zip"
  }
}

