  name                         = "PizzaOrderingBot"
  description                  = "Bot for ordering pizza"
  process_behavior             = "BUILD"
  locale                       = "en-US"
  child_directed               = false
  idle_session_ttl_in_seconds  = 300

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I am unable to assist with your pizza order at this time."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't quite catch that. Would you like to order a pizza?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I'd like to order a pizza",
    "Can I get a pizza",
    "Order a {PizzaSize} {PizzaType} pizza"
  ]

  slot {
    name     = "PizzaType"
    priority = 1
    slot_constraint = "Required"
    slot_type       = "AMAZON.Food"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What kind of pizza would you like?"
      }
    }
  }

  slot {
    name     = "PizzaSize"
    priority = 2
    slot_constraint = "Required"
    slot_type       = "AMAZON.AlphaNumeric"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size pizza would you like (Small, Medium, or Large)?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  # Follow-up prompt after the pizza order is fulfilled
  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "Your {PizzaSize} {PizzaType} pizza is on the way! Would you like to add a drink to your order?"
      }
    }

    rejection_statement {
      message {
        content_type = "PlainText"
        content      = "No problem. Enjoy your pizza!"
      }
    }
  }
}

