resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Buy a pizza",
    "Can I order a {PizzaType} pizza"
  ]

  slot {
    name     = "PizzaType"
    priority = 1
    required = true
    slot_type = "AMAZON.AlphaNumeric"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What type of pizza would you like to order?"
      }
    }
  }

  slot {
    name     = "PizzaSize"
    priority = 2
    required = true
    slot_type = "AMAZON.AlphaNumeric"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content_type = "PlainText"
        content      = "What size pizza would you like: Small, Medium, or Large?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Great! I have placed your order for a {PizzaSize} {PizzaType} pizza. Your meal will be ready in 20 minutes."
    }
  }
}

resource "aws_lex_bot" "pizza_bot" {
  name                         = "PizzaOrderingBot"
