  child_directed               = false
  idle_session_ttl_in_seconds  = 300

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I am unable to assist with your pizza order at this time."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't quite catch that. Can you say that again?"
    }
  }
}
