resource "aws_iam_role" "lex_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Can I have a pizza please",
    "I'm hungry for pizza"
  ]

  slot {
    name              = "PizzaSize"
    slot_constraint   = "Required"
    slot_type         = "AMAZON.AlphaNumeric"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? We have small, medium, and large!"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name              = "Topping"
    slot_constraint   = "Required"
    slot_type         = "AMAZON.AlphaNumeric"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What is your favorite topping? Cheese, pepperoni, or veggies?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay! So you want a {PizzaSize} {Topping} pizza. Is that right?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "No problem, we can start over when you are ready."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "pizza_bot" {
  name                        = "ChildrensPizzaBot"
  child_directed              = true
  description                 = "A friendly bot for children to practice ordering pizza"
  locale                      = "en-US"
  process_behavior            = "BUILD"
  idle_session_ttl_in_seconds = 300

  abort_statement {
    message {
      content      = "I'm sorry, I'm having trouble helping you. Maybe ask a grown-up for help!"
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't quite catch that. Can you say that again? You can say 'I want a pizza'."
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }
}

