        }
      },
    ]
  })
}

resource "aws_lambda_function" "pizza_order_handler" {
  filename      = "lambda_function_payload.zip"
  function_name = "pizza_order_handler"
  role          = aws_iam_role.lex_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_handler.function_name
  principal     = "lex.amazonaws.com"
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      message_version = "1.0"
      uri             = aws_lambda_function.pizza_order_handler.arn
    }
  }

  sample_utterances = [
    "I would like to order a pizza",
    "Can I get a pizza",
    "Order a pizza"
  ]

  slot {
    name             = "PizzaSize"
    description      = "The size of the pizza"
    slot_constraint  = "Required"
    slot_type        = "AMAZON.AlphaNumeric"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_bot" "pizza_bot" {
  name                         = "PizzaOrderBot"
  child_directed               = false
  create_version               = true
  description                  = "Bot for ordering pizza"
  idle_session_ttl_in_seconds  = 300

  abort_statement {
    message {
      content      = "I'm sorry, I am unable to assist with your pizza order at this time."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand that. Can you please repeat your pizza choice?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "1"
  }
}

