resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.kids_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.70

  voice_settings {
    voice_id = "Ivy" # A child-like voice from Polly
    engine   = "neural"
