  bot_id      = aws_lexv2models_bot.kids_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "HelloIntent"

  sample_utterance { utterance = "Hi" }
  sample_utterance { utterance = "Hello" }
  sample_utterance { utterance = "Hey there" }

  initial_response_setting {
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Hi! I'm your friendly robot pal. What's your name?"
          }
        }
      }
    }
  }
}

