resource "aws_kinesis_stream" "example_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24
}

resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:Get*",
          "kinesis:DescribeStream",
          "kinesis:ListStreams"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.example_stream.arn
      },
    ]
  })
}

resource "aws_kinesis_analytics_application" "example_application" {
  name = "example-analytics-application"

  inputs {
    name_prefix = "example_input_prefix"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.example_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      data_format = "JSON"

      record_columns {
        mapping  = "$.sensor_id"
        name     = "SENSOR_ID"
        sql_type = "VARCHAR(64)"
      }

      record_columns {
        mapping  = "$.temperature"
        name     = "TEMPERATURE"
        sql_type = "DOUBLE"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  code = <<EOF
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id VARCHAR(64), temperature DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM "SENSOR_ID", "TEMPERATURE"
FROM "SOURCE_SQL_STREAM_001"
WHERE "TEMPERATURE" > 20;
EOF
}

