# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Obtain the active caller identity
data "aws_caller_identity" "current" {}

# Get the most recent stable ECR image tag (example repository name)
data "aws_ecr_image" "service_image" {
  repository_name = "my-app-repo"
  image_tag       = "stable"
}

# Declare locals for metadata and tags
locals {
  cluster_name = "eks-cluster-${terraform.workspace}"
  image_tag    = data.aws_ecr_image.service_image.image_tag
  common_tags = {
    Environment = terraform.workspace
    Project     = "Infrastructure"
    ManagedBy   = "Terraform"
  }
}

# Create an EKS module for cluster provisioning
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = local.cluster_name
  cluster_version = "1.27"

  vpc_id     = "vpc-12345678"
  subnet_ids = ["subnet-abc123", "subnet-def456"]

  eks_managed_node_groups = {
    default = {
      min_size       = 1
      max_size       = 3
      desired_size   = 2
      instance_types = ["t3.medium"]
      iam_role_additional_policies = {
        AmazonSSMManagedInstanceCore = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
      }
    }
  }

  tags = local.common_tags
}

# Fetch resulting EKS cluster metadata and auth details
data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_name
}

# Set up the Kubernetes provider
provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

# Set up the Helm provider
provider "helm" {
  kubernetes {
    host                   = module.eks.cluster_endpoint
    cluster_ca_certificate = base64decode(module.eks.cluster_certificate_authority_data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

