resource "random_id" "bucket_suffix" {
  count       = 2
  byte_length = 4
}

resource "aws_s3_bucket" "logging_target" {
  bucket = "logs-destination-${random_id.bucket_suffix[0].hex}"
}

resource "aws_s3_bucket" "source_bucket" {
  bucket = "app-data-source-${random_id.bucket_suffix[1].hex}"
}

resource "aws_s3_bucket_ownership_controls" "logging_target_oc" {
  bucket = aws_s3_bucket.logging_target.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "logging_target_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.logging_target_oc]

  bucket = aws_s3_bucket.logging_target.id
  acl    = "log-delivery-write"
}

resource "aws_s3_bucket_ownership_controls" "source_bucket_oc" {
  bucket = aws_s3_bucket.source_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "source_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.source_bucket_oc]

  bucket = aws_s3_bucket.source_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_logging" "example" {
  bucket = aws_s3_bucket.source_bucket.id

  target_bucket = aws_s3_bucket.logging_target.id
  target_prefix = "log/system-access/"

  # Ensure ACL is set to log-delivery-write before enabling logging
  depends_on = [aws_s3_bucket_acl.logging_target_acl]
}
