# IAM Role for Lambda
resource "aws_iam_role" "iam_for_lambda" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# Dummy archive for the Lambda function
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"
  source {
    content  = "exports.handler = async (event) => { console.log('Scheduled task running'); };"
    filename = "index.js"
  }
}

# AWS Lambda Function
resource "aws_lambda_function" "scheduled_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "fifteen_minute_task"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# EventBridge Rule (Cron 15 minutes)
resource "aws_cloudwatch_event_rule" "every_fifteen_minutes" {
  name                = "every-fifteen-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# EventBridge Target
resource "aws_cloudwatch_event_target" "check_lambda_every_fifteen_minutes" {
  rule      = aws_cloudwatch_event_rule.every_fifteen_minutes.name
  target_id = "lambda"
  arn       = aws_lambda_function.scheduled_lambda.arn
}

# Lambda Permission to allow EventBridge to trigger it
resource "aws_lambda_permission" "allow_cloudwatch_to_call_lambda" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_fifteen_minutes.arn
}

