extracted_code:
# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# Get latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]
  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
}

# Security Group for Instances
resource "aws_security_group" "ec2_sg" {
  name   = "ec2-efs-sg"
  vpc_id = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for EFS (Allows NFS from EC2 SG)
resource "aws_security_group" "efs_sg" {
  name   = "efs-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }
}

# Amazon EFS File System
resource "aws_efs_file_system" "shared_storage" {
  creation_token = "shared-storage"
  tags = {
    Name = "SharedStorage"
  }
}

# EFS Mount Targets in each Private Subnet
resource "aws_efs_mount_target" "mount" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared_storage.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs_sg.id]
}

# EC2 Instances
resource "aws_instance" "app_server" {
  count                  = 2
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  # User data to install amazon-efs-utils and mount the drive
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir -p /mnt/efs
              mount -t efs -o tls ${aws_efs_file_system.shared_storage.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared_storage.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "AppServer-${count.index + 1}"
  }

  depends_on = [aws_efs_mount_target.mount]
}

