# Create an IAM role for the ElastiCache user
resource "aws_iam_role" "elasticache_user_role" {
  name = "ElastiCacheIAMUserRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# Create a policy to allow connecting to ElastiCache via IAM
resource "aws_iam_policy" "elasticache_connect" {
  name        = "ElastiCacheIAMConnectPolicy"
  description = "Allows connecting to ElastiCache using IAM authentication"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "elasticache:Connect"
        Effect   = "Allow"
        Resource = "arn:aws:elasticache:*:*:user:${aws_elasticache_user.iam_user.user_id}"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach_connect" {
  role       = aws_iam_role.elasticache_user_role.name
  policy_arn = aws_iam_policy.elasticache_connect.arn
}

# Create an ElastiCache User with authentication_mode set to iam
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-user-01"
  user_name     = "iam_user_name"
  engine        = "REDIS"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "iam"
  }
}

# Create a User Group and add the IAM-enabled user
resource "aws_elasticache_user_group" "example" {
  engine        = "REDIS"
  user_group_id = "user-group-01"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# Provision a Replication Group with Transit Encryption enabled (Required for IAM auth)
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "iam-auth-cluster"
  description                = "Redis cluster with IAM authentication"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 1
  port                       = 6379
  transit_encryption_enabled = true
  user_group_ids             = [aws_elasticache_user_group.example.user_group_id]
}

