  bucket = aws_s3_bucket.msk_logs_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip"
}

resource "aws_mskconnect_custom_plugin" "example" {
  name         = "debezium-plugin"
  content_type = "ZIP"
  location {
