# This configuration demonstrates setting up a Time to Live (TTL) field 
# in an AWS DynamoDB table to automatically manage data expiration.

resource "aws_dynamodb_table" "example" {
  name             = "UserSessions"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "SessionId"

  attribute {
    name = "SessionId"
    type = "S"
  }

  # TTL configuration: Defines the attribute name that stores the expiration timestamp
  ttl {
    attribute_name = "ExpiresAt"
    enabled        = true
  }

  tags = {
    Environment = "production"
    Name        = "SessionStore"
  }
}

# Example of how objects should be stored (Conceptual/Documentation):
# Item = {
#   "SessionId": "abc-123",
#   "ExpiresAt": 1672531200  // Unix timestamp (Seconds)
# }

