  vpc_id     = aws_vpc.main.id
  subnet_ids = [aws_subnet.main.id]

  # Inbound Rules
  ingress {
    protocol   = "tcp"
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 80
    to_port    = 80
