  bucket = "my-source-data-bucket"
}

resource "aws_s3_bucket" "inventory" {
  bucket = "my-inventory-reports-bucket"
}

resource "aws_s3_bucket_policy" "inventory_policy" {
  bucket = aws_s3_bucket.inventory.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowS3InventoryToWrite"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory.arn}/*"
        Condition = {
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.source.arn
          }
        }
      }
    ]
  })
}

resource "aws_s3_bucket_inventory" "source_inventory" {
  bucket = aws_s3_bucket.source.id
  name   = "weekly-inventory-csv"

  included_object_versions = "All"

  schedule {
    frequency = "Weekly"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory.arn
      prefix     = "inventory-reports"
    }
  }
}
```

