}

# CodeBuild Project to execute the grading environment
resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder-${random_id.suffix.hex}"
  description   = "Executes student code from GitHub and records results"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.grading_artifacts.bucket
    name     = "grading-output"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_MODE"
      value = "STRICT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/course-org/student-repo-template.git"
    git_clone_depth = 1

    # buildspec can be embedded or fetched from the repo
    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing dependencies..."
      - pip install -r requirements.txt
  build:
    commands:
      - echo "Running student tests..."
      - python3 grader.py > results.json
artifacts:
  files:
    - results.json
EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "grading-session"
    }
  }
}

# Webhook to trigger build on student push
resource "aws_codebuild_webhook" "github_trigger" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
  }
}

