resource "aws_s3_bucket" "grading_artifacts" {
  bucket = "grading-system-outputs-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# --- IAM Role for CodeBuild ---
resource "aws_iam_role" "codebuild_role" {
  name = "grading-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Resource = ["*"]
      },
      {
        Effect   = "Allow"
        Action   = ["s3:PutObject", "s3:GetObject", "s3:GetBucketLocation"]
        Resource = ["${aws_s3_bucket.grading_artifacts.arn}/*"]
      },
      {
        Effect   = "Allow"
        Action   = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# --- CodeBuild Project ---
resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder"
  description   = "Executes student submissions in an isolated VPC environment"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.grading_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/university/student-submission-repo.git"
    git_clone_depth = 1
    # Buildspec defines the grading commands and where to output results
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Starting isolated grading..."
            - chmod +x ./grade.sh
            - ./grade.sh > results.txt
      artifacts:
        files:
          - results.txt
    EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.isolated_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }
}

