# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# S3 Bucket to store grading outputs and artifacts
resource "aws_s3_bucket" "grading_reports" {
  bucket        = "autograder-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Network Infrastructure: VPC, Subnet, and Security Group
resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "isolated_subnet" {
  vpc_id            = aws_vpc.grading_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-isolated-subnet"
  }
}

# Security Group to BLOCK all outbound internet access
resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg"
  description = "Block all outbound traffic except internal AWS VPC traffic"
  vpc_id      = aws_vpc.grading_vpc.id

  # Allow internal egress if needed for specific internal services, 
  # but by omitting standard 0.0.0.0/0 egress, all internet traffic is blocked.
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.grading_vpc.cidr_block]
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild Project for execution
resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder"
  description   = "Executes student submissions in a locked-down VPC environment"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/organization/student-repo.git"
    git_clone_depth = 1
    buildspec       = <<EOF
version: 0.2
phases:
  build:
    commands:
      - echo "Running Autograder..."
      - # Run tests and generate report
      - python3 grader.py > grading_report.json
  post_build:
    commands:
      - aws s3 cp grading_report.json s3://$${REPORT_BUCKET}/$${CODEBUILD_BUILD_ID}.json
EOF
  }

  environment_variable {
    name  = "REPORT_BUCKET"
    value = aws_s3_bucket.grading_reports.id
  }

  vpc_config {
    vpc_id             = aws_vpc.grading_vpc.id
    subnets            = [aws_subnet.isolated_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }
}

