resource "aws_s3_bucket" "cat_photos" {
  bucket        = "cat-photo-storage-${random_id.suffix.hex}"
  force_destroy = true
}

# Public access block for the bucket
resource "aws_s3_bucket_public_access_block" "cat_photos_access" {
  bucket = aws_s3_bucket.cat_photos.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# IAM Role for API Gateway to push to S3
resource "aws_iam_role" "api_gateway_s3_role" {
  name = "api_gateway_s3_role_${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "apigateway.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "s3_policy" {
  name = "s3_access_policy"
  role = aws_iam_role.api_gateway_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject"]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.cat_photos.arn}/*"
      }
    ]
  })
}

