  name        = "ec2_backup_vault"
  kms_key_arn = aws_kms_key.backup_key.arn
}

# Create a Backup Plan
resource "aws_backup_plan" "daily_backup" {
  name = "daily_ec2_backup_plan"

  rule {
    rule_name         = "daily_midnight_backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 0 * * ? *)" # Every day at 12:00 AM UTC

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

