```hcl
# Create a KMS key for encrypting the backup vault
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for AWS Backup"
  deletion_window_in_days = 10
}

# Create an AWS Backup Vault
resource "aws_backup_vault" "daily_vault" {
  name        = "ec2_daily_backup_vault"
  kms_key_arn = aws_kms_key.backup_key.arn
}

# Create the Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily_ec2_backup_plan"

  rule {
    rule_name         = "daily_midnight_backup"
    target_vault_name = aws_backup_vault.daily_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at 12:00 AM UTC

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# IAM Role for AWS Backup to assume
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# Associate the EC2 instance with the backup plan using tags
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_ec2_selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

# Launch the EC2 Instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c55b159cbfafe1f0" # Replace with valid AMI for your region
  instance_type = "t3.micro"

  tags = {
    Name   = "BackupTargetInstance"
    Backup = "Daily" # This tag ensures it is picked up by the Backup Selection
  }
}
```

