# EventBridge rule to trigger at 07:00 UTC daily
resource "aws_cloudwatch_event_rule" "daily_trigger" {
  name                = "daily-seven-am-trigger"
  description         = "Triggers at 07:00 UTC every day"
  schedule_expression = "cron(0 7 * * ? *)"
}

# Set the Lambda function as the target for the EventBridge rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_trigger.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.scheduled_task.arn
}

# Allow EventBridge to call the Lambda function
resource "aws_lambda_permission" "allow_cloudwatch_to_call_lambda" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_trigger.arn
}

