# Define local variables for naming and tagging
locals {
  name   = "video-streaming-platform"
  region = "us-east-1"
  tags = {
    Project     = "VideoStreaming"
    Environment = "Production"
  }
}

# Create a VPC using the official module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = local.name
  cidr = "10.0.0.0/16"

  azs             = ["${local.region}a", "${local.region}b", "${local.region}c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = local.tags
}

# Security Group for Load Balancer (Public Access)
resource "aws_security_group" "alb_sg" {
  name        = "${local.name}-alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for EC2 Instances (From ALB only)
resource "aws_security_group" "ec2_sg" {
  name        = "${local.name}-ec2-sg"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Application Load Balancer
resource "aws_lb" "video_alb" {
  name               = "${local.name}-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  tags = local.tags
}

# Target Group for Video Servers
resource "aws_lb_target_group" "video_tg" {
  name     = "${local.name}-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# ALB Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.video_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_tg.arn
  }
}

# EC2 Instances for Video Processing/Streaming
resource "aws_instance" "video_server" {
  count         = 3
  ami           = "ami-0c7217cdde317cfec" # Amazon Linux 2 (Example ID)
  instance_type = "t3.medium"
  subnet_id     = element(module.vpc.private_subnets, count.index)
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Server ${count.index + 1}</h1>" > /var/www/html/index.html
              EOF

  tags = merge(local.tags, { Name = "${local.name}-server-${count.index}" })
}

# Attach EC2 instances to Target Group
resource "aws_lb_target_group_attachment" "attachment" {
  count            = 3
  target_group_arn = aws_lb_target_group.video_tg.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 80
}

# Route53 Infrastructure
resource "aws_route53_zone" "primary" {
  name = "mystreamingplatform.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.mystreamingplatform.com"
  type    = "A"

  alias {
    name                   = aws_lb.video_alb.dns_name
    zone_id                = aws_lb.video_alb.zone_id
    evaluate_target_health = true
  }
}

