response:
```hcl
# Create the VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dolphinscheduler-vpc"
  }
}

# Create Public Subnets (at least 2 in different AZs for RDS Subnet Group)
resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-1"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-2"
  }
}

# DB Subnet Group required for RDS in a VPC
resource "aws_db_subnet_group" "db_group" {
  name       = "dolphinscheduler-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "dolphinscheduler-db-subnet-group"
  }
}

# Security Group for Database Access
resource "aws_security_group" "db_access" {
  name        = "database-access-sg"
  description = "Security group for PostgreSQL access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random password for RDS
resource "random_password" "db_password" {
  length  = 16
  special = false
}

# PostgreSQL 17.1 Instance
resource "aws_db_instance" "dolphinscheduler" {
  identifier           = "dolphinscheduler"
  allocated_storage    = 5
  engine               = "postgres"
  engine_version       = "17.1"
  instance_class       = "db.t3.micro"
  db_name              = "dolphinscheduler"
  username             = "postgres"
  password             = random_password.db_password.result
  db_subnet_group_name = aws_db_subnet_group.db_group.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  skip_final_snapshot  = true

  tags = {
    Name = "dolphinscheduler-db"
  }
}
```

