    }
    option_settings {
      name  = "S3_BUCKET_ARN"
      value = "arn:aws:s3:::testbucketineu-west2/rds"
    }
  }

  option {
    option_name = "TDE"
    port        = 0
  }

  tags = {
    pike = "permissions"
  }
}

