{
    "Version":"2012-10-17",
    "Statement":[
      {
        "Sid": "add-read-only-permissions",
        "Principal": "*",
        "Effect": "Allow",
        "Action": [
          "glacier:GetVaultNotifications",
          "glacier:DescribeVault"
        ],
        "Resource": "arn:aws:glacier:*:*:vaults/long-term-storage-vault"
      }
    ]
}
EOF

  tags = {
    Environment = "Archive"
    Purpose     = "LongTermDataStorage"
  }
}

resource "aws_glacier_vault_lock" "example" {
  complete_lock = false
  vault_name    = aws_glacier_vault.archive_vault.name

  policy = <<EOF
{
  "Version":"2012-10-17",
  "Statement":[
    {
      "Sid": "deny-delete-after-locked",
      "Principal": "*",
      "Effect": "Deny",
      "Action": "glacier:DeleteArchive",
      "Resource": "${aws_glacier_vault.archive_vault.arn}",
      "Condition": {
        "NumericLessThan": {
          "glacier:ArchiveAgeInDays": "365"
        }
      }
    }
  ]
}
EOF
}

