# Generate a random suffix for unique naming
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# S3 Bucket for primary storage/backups
resource "aws_s3_bucket" "backup_storage" {
  bucket = "long-term-backups-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Long Term Retention Storage"
    Environment = "Production"
    Purpose     = "Backup"
  }
}

# Enable versioning to protect against accidental deletes/overwrites
resource "aws_s3_bucket_versioning" "backup_versioning" {
  bucket = aws_s3_bucket.backup_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Lifecycle rules for long-term data retention and cost optimization
resource "aws_s3_bucket_lifecycle_configuration" "backup_lifecycle" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "archive-to-glacier"
    status = "Enabled"

    # Transition to Standard-IA after 30 days
    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    # Transition to Glacier Flexible Retrieval for long-term retention after 90 days
    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    # Move to Deep Archive after 180 days for maximum cost savings
    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    # Expire objects older than 7 years (2555 days)
    expiration {
      days = 2555
    }
  }
}

# Block all public access for security compliance
resource "aws_s3_bucket_public_access_block" "backup_security" {
  bucket = aws_s3_bucket.backup_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable server-side encryption by default
resource "aws_s3_bucket_server_side_encryption_configuration" "backup_encryption" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

