# Terraform configuration for a minimal PostgreSQL instance on AWS RDS
# Optimized for minimal memory usage and cost

resource "random_id" "db_suffix" {
  byte_length = 4
}

resource "random_password" "db_password" {
  length  = 16
  special = false
}

resource "aws_db_parameter_group" "low_memory" {
  family = "postgres15"
  name   = "low-memory-config-${random_id.db_suffix.hex}"

  # Reducing shared buffers (default is usually 25% of RAM)
  parameter {
    name  = "shared_buffers"
    value = "{DBInstanceClassMemory/16384}" # Reduced allocation
  }

  # Reducing work_mem to limit memory per-operation
  parameter {
    name  = "work_mem"
    value = "4096" # 4MB
  }

  # Reduce max connections to lower memory overhead
  parameter {
    name  = "max_connections"
    value = "20"
  }
}

resource "aws_db_instance" "minimal_pg" {
  identifier           = "minimal-pg-${random_id.db_suffix.hex}"
  engine               = "postgres"
  engine_version       = "15.4"

  # t4g.micro is the smallest instance type (Graviton2, 2 vCPU, 1GB RAM)
  instance_class       = "db.t4g.micro"

  allocated_storage    = 20
  storage_type         = "gp3"

  db_name              = "minimaldb"
  username             = "postgres"
  password             = random_password.db_password.result

  parameter_group_name = aws_db_parameter_group.low_memory.name

  publicly_accessible  = false
  skip_final_snapshot  = true

  performance_insights_enabled = false # Disabled to save resources
  monitoring_interval          = 0     # Disabled Enhanced Monitoring
}

